#include <stdio.h>
#include <math.h>

void getFactors(int x, int factors[], int *count) {
    *count = 0;
    for (int i = 1; i <= sqrt(x); i++) {
        if (x % i == 0) {
            factors[(*count)++] = i;
        }
    }
}

int main() {
    int n;
    scanf("%d", &n);

    int factors[1000];
    int count;
    getFactors(n, factors, &count);

    int b = n / factors[count - 1];
    int a = n / b;

    printf("%d %d", a, b);
    return 0;
}
